 91→    private Set<Long> getStarredSpaceNodeSet(Long userId) {
 92→        if(userId == null) return new HashSet<>();
 93→        List<SpaceNodeStarEntity> starEntities = spaceNodeStarService.getByUserId(userId);
 94→        if (CollectionUtils.isEmpty(starEntities)) return new HashSet<>();
 95→        return starEntities.stream().map(SpaceNodeStarEntity::getSpaceNodeId).collect(Collectors.toSet());
 96→    }
 97→
 98→    public List<SpaceNodeVo> toSpaceNodeOnlyInAio(List<SpaceNodeEntity> entities) {
 99→        if(CollectionUtils.isEmpty(entities)) return List.of();
100→        return entities.stream()
101→                .map(e -> new SpaceNodeVo(e, null, null, null, e.getIcon()))
102→                .toList();
103→    }
