 76→                        Map<Integer, List<SpaceAppRelEntity>> thirdAppMap = thirdAppGroupMap.get(e.getSpaceId());
 77→                        if(Objects.equals(e.getType(), SpaceNodeTypeEnum.AFFINE.getValue())
 78→                                &&CollectionUtils.isNotEmpty(thirdAppMap.get(SpaceAppTypeEnum.AFFINE.getValue())))
 79→                            appSpaceId=thirdAppMap.get(SpaceAppTypeEnum.AFFINE.getValue()).getFirst().getAppSpaceId();
 80→                    }
 81→                    return new SpaceNodeVo(e, creatorName, isStarred, appSpaceId, e.getIcon());
 82→                })
 83→                .toList();
 84→        long t3 = System.currentTimeMillis();
 85→        log.info("[2009-perf][toSpaceNodeVo] streamMapping(nicknames)={}ms entityCount={}", t3 - t2, entities.size());
 86→
 87→        // 填充个人标签：查询当前用户在这批节点上的标签关系，再批量获取标签定义
