114→    /**
115→     * 批量填充个人标签到 VO 列表。
116→     * 1. 收集所有节点 ID，批量查询当前用户的标签关联关系
117→     * 2. 若有关联，批量查询标签定义，按节点分组后写入各 VO
118→     */
119→    private void enrichTags(List<SpaceNodeVo> vos, Long userId) {
120→        if (userId == null || CollectionUtils.isEmpty(vos)) return;
121→
122→        Set<Long> nodeIds = vos.stream().map(SpaceNodeVo::getId).collect(Collectors.toSet());
123→        List<SpaceNodeTagRelEntity> relList = spaceNodeTagRelService.listBySpaceNodeIdsAndUserId(nodeIds, userId);
124→        if (CollectionUtils.isEmpty(relList)) return;
125→
126→        // 批量取标签定义，并建立 tagId -> tag 的快速查找 Map
127→        Set<Long> tagIds = relList.stream().map(SpaceNodeTagRelEntity::getTagId).collect(Collectors.toSet());
128→        List<SpaceNodeTagEntity> tagEntities = spaceNodeTagService.listByIds(tagIds);
129→        Map<Long, SpaceNodeTagEntity> tagMap = tagEntities.stream()
130→                .collect(Collectors.toMap(SpaceNodeTagEntity::getId, t -> t));
131→
132→        // 按 spaceNodeId 分组，将标签列表写入对应 VO
133→        Map<Long, List<SpaceNodeTagRelEntity>> relsByNodeId = relList.stream()
134→                .collect(Collectors.groupingBy(SpaceNodeTagRelEntity::getSpaceNodeId));
135→
136→        for (SpaceNodeVo vo : vos) {
137→            List<SpaceNodeTagRelEntity> rels = relsByNodeId.get(vo.getId());
138→            if (CollectionUtils.isEmpty(rels)) continue;
139→            List<SpaceNodeTagVo> tagVos = rels.stream()
140→                    .map(rel -> tagMap.get(rel.getTagId()))
141→                    .filter(Objects::nonNull)
142→                    .map(tag -> SpaceNodeTagVo.builder()
143→                            .id(tag.getId())
144→                            .name(tag.getName())
145→                            .color(tag.getColor())
146→                            .sortOrder(tag.getSortOrder())
147→                            .build())
148→                    .collect(Collectors.toList());
149→            vo.setTags(tagVos);
150→        }
151→    }
